from google.adk.agents import Agent
from google.adk.sessions import Session
import re

JAILBREAK_PATTERNS = [
    r'(ignore|forget|override).*?(instructions|rules|policy)',
    r'(you are|pretend).*?(hacker|DAN|developer mode)',
    r'base64_decode|eval\(|exec\(|__import__',
    r'(sudo|root|admin).*?(access|permissions)'
]

def scan_for_jailbreaks(message: str, source: str = 'user') -> dict:
    findings = []
    for pattern in JAILBREAK_PATTERNS:
        matches = re.finditer(pattern, message, re.IGNORECASE)
        for match in matches:
            findings.append({
                'pattern': pattern,
                'match': match.group(0),
                'source': source,
                'confidence': 0.9
            })
    return {'suspicious': len(findings) > 0, 'findings': findings}

# Usage in ADK agent
def before_agent_callback(session: Session, agent: Agent, message: str) -> bool:
    result = scan_for_jailbreaks(message)
    if result['suspicious']:
        print(f'🚨 Jailbreak detected: {result["findings"]}')
        return False
    return True
